import React, { useState } from "react";
import { Link } from "react-router-dom";
import {
  Box,
  Container,
  Typography,
  Breadcrumbs,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  Paper,
  Stack,
  Divider,
} from "@mui/material";

import NavigateNextIcon from "@mui/icons-material/NavigateNext";
import ExpandMoreIcon from "@mui/icons-material/ExpandMore";
import GavelIcon from "@mui/icons-material/Gavel";
import SupportAgentIcon from "@mui/icons-material/SupportAgent";
import AccessTimeIcon from "@mui/icons-material/AccessTime";
import AccountBalanceIcon from "@mui/icons-material/AccountBalance";

function GrievancePolicy() {
  const [expanded, setExpanded] = useState("panel1");

  const handleChange = (panel) => (event, isExpanded) => {
    setExpanded(isExpanded ? panel : false);
  };

  const sections = [
    {
      id: "panel1",
      icon: <GavelIcon />,
      title: "Objective of Grievance Policy",
      color: "#1976d2",
      content:
        "Techmoney Solutions Private Limited (operating as BankMudraa) is committed to providing secure, transparent and efficient financial services. This Grievance Redressal Policy ensures that customer complaints are handled in a timely, fair and compliant manner in accordance with RBI, NPCI and applicable regulatory guidelines.",
    },
    {
      id: "panel2",
      icon: <SupportAgentIcon />,
      title: "How to Raise a Complaint",
      color: "#2e7d32",
      content:
        "Users may raise complaints related to AEPS, BBPS, Money Transfer, Recharge, Insurance, Wallet transactions or any service offered by BankMudraa through email or official communication channels. Customers must provide transaction details, registered mobile number and relevant supporting information for faster resolution.",
    },
    {
      id: "panel3",
      icon: <AccessTimeIcon />,
      title: "Resolution Timeline",
      color: "#ed6c02",
      content:
        "All grievances will be acknowledged within 24–48 working hours. Resolution will typically be provided within 7 working days. In cases requiring third-party dependency (banks, NPCI, BBPS, etc.), resolution may take up to 30 days as per regulatory framework.",
    },
    {
      id: "panel4",
      icon: <AccountBalanceIcon />,
      title: "Escalation Matrix",
      color: "#9c27b0",
      content:
        "Level 1: Customer Support Team\nLevel 2: Nodal Officer – BankMudraa\nLevel 3: If the grievance remains unresolved within 30 days, the customer may escalate the matter to the respective regulated partner bank or approach the RBI Ombudsman under the Integrated Ombudsman Scheme, 2021, as applicable.",
    },
    {
      id: "panel5",
      icon: <SupportAgentIcon />,
      title: "Grievance Redressal & Nodal Officer",
      color: "#d32f2f",
      content:
        "In accordance with the Information Technology Act and RBI guidelines, users may contact our Nodal Officer for unresolved disputes.\n\nNodal Officer Name: Rohit Sharma\nDesignation: Nodal Officer - BankMudraa\nEmail: grievance@bankmudraa.com",
    },
    {
      id: "panel6",
      icon: <GavelIcon />,
      title: "Regulatory Compliance",
      color: "#0288d1",
      content:
        "BankMudraa operates in compliance with applicable RBI circulars, NPCI operating guidelines, BBPS standards and Information Technology Act provisions. All customer data and grievance handling processes follow secure and regulated practices.",
    },
  ];

  return (
    <Box sx={{ bgcolor: "#f8f9fa", minHeight: "100vh" }}>
      
      {/* HERO SECTION */}
      <Box
        sx={{
          background:
            "linear-gradient(135deg, rgb(23,59,75) 0%, #23627e 100%)",
          position: "relative",
          overflow: "hidden",
          py: { xs: 6, md: 10 },
          color: "#fff",
          "&::before": {
            content: '""',
            position: "absolute",
            inset: 0,
            backgroundImage:
              "radial-gradient(circle at 20% 50%, rgba(255,255,255,0.1) 0%, transparent 50%), radial-gradient(circle at 80% 80%, rgba(255,255,255,0.1) 0%, transparent 50%)",
          },
        }}
      >
        <Container maxWidth="lg" sx={{ position: "relative", zIndex: 1 }}>
          <Breadcrumbs
            separator={
              <NavigateNextIcon
                fontSize="small"
                sx={{ color: "rgba(255,255,255,0.7)" }}
              />
            }
            sx={{ mb: 3 }}
          >
            <Link
              to="/"
              style={{
                color: "rgba(255,255,255,0.9)",
                textDecoration: "none",
              }}
            >
              Home
            </Link>
            <Typography sx={{ color: "white" }}>
              Grievance Policy
            </Typography>
          </Breadcrumbs>

          <Typography
            variant="h2"
            sx={{
              fontWeight: 700,
              fontSize: { xs: "2rem", md: "3rem" },
            }}
          >
            Grievance Redressal Policy
          </Typography>

          <Typography
            variant="h6"
            sx={{
              mt: 2,
              maxWidth: 700,
              color: "rgba(255,255,255,0.95)",
            }}
          >
            Our commitment to fair, transparent and timely complaint resolution.
          </Typography>
        </Container>
      </Box>

      {/* CONTENT */}
      <Container maxWidth="lg" sx={{ py: { xs: 4, md: 6 } }}>
        
        {/* Overview Card */}
        <Paper
          elevation={0}
          sx={{
            p: 4,
            mb: 4,
            borderRadius: 3,
            border: "1px solid",
            borderColor: "divider",
            boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
          }}
        >
          <Typography variant="h5" fontWeight={600} gutterBottom>
            Policy Overview
          </Typography>
          <Typography variant="body2" color="text.secondary">
            This Grievance Redressal Policy outlines the process for addressing
            customer complaints related to services offered by BankMudraa.
            We aim to resolve all concerns efficiently while maintaining
            compliance with regulatory standards.
          </Typography>
        </Paper>

        {/* ACCORDIONS */}
        {sections.map((section) => (
          <Accordion
            key={section.id}
            expanded={expanded === section.id}
            onChange={handleChange(section.id)}
            sx={{
              mb: 2,
              borderRadius: "12px !important",
              border: "1px solid",
              borderColor: "divider",
              "&:before": { display: "none" },
              "&.Mui-expanded": {
                boxShadow: `0 4px 20px ${section.color}20`,
                border: `2px solid ${section.color}`,
              },
            }}
          >
            <AccordionSummary
              expandIcon={<ExpandMoreIcon />}
              sx={{
                "& .MuiAccordionSummary-content": {
                  alignItems: "center",
                  gap: 2,
                  my: 1.5,
                },
                bgcolor:
                  expanded === section.id
                    ? `${section.color}08`
                    : "transparent",
              }}
            >
              <Box
                sx={{
                  width: 48,
                  height: 48,
                  borderRadius: 2,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  bgcolor: `${section.color}15`,
                  color: section.color,
                  flexShrink: 0,
                }}
              >
                {section.icon}
              </Box>

              <Typography fontWeight={600}>
                {section.title}
              </Typography>
            </AccordionSummary>

            <AccordionDetails sx={{ bgcolor: "#fafafa" }}>
              <Typography
                variant="body2"
                color="text.secondary"
                sx={{ whiteSpace: "pre-line", lineHeight: 1.7 }}
              >
                {section.content}
              </Typography>
            </AccordionDetails>
          </Accordion>
        ))}
      </Container>
    </Box>
  );
}

export default GrievancePolicy;